import React, { useState } from "react";
import Upload from "./components/Upload";

function App() {
  const [urls, setUrls] = useState([]);
  const [index, setIndex] = useState(0);

  return (
    <div style={{ textAlign: "center" }}>
      <h1>🌐 URL Navigator</h1>

      <Upload setUrls={setUrls} />

      {urls.length > 0 && (
        <>
          <iframe
            src={urls[index]}
            width="80%"
            height="400px"
            title="viewer"
          />

          <div>
            <button onClick={() => setIndex(Math.max(index - 1, 0))}>
              Prev
            </button>
            <button onClick={() => setIndex(Math.min(index + 1, urls.length - 1))}>
              Next
            </button>
          </div>
        </>
      )}
    </div>
  );
}

export default App;
